using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
string s,t="123804765";
map<string,int> v;
int d[5]={-1,1,-3,3};
int h(string a)
{
    char c[3][3],e[3][3]={{'1','2','3'},{'8','0','4'},{'7','6','5'}};
    FOR(i,0,2)FOR(j,0,2)c[i][j]=a[i*3+j];
    int r=0;
    FOR(i,0,2)FOR(j,0,2)
    {
        if(c[i][j]=='0')continue;
        FOR(x,0,2)FOR(y,0,2)if(e[x][y]==c[i][j])r+=abs(i-x)+abs(j-y);
    }
    return r;
}
struct dot
{
    string s;
    int st;
    friend bool operator<(const dot&a,const dot&b)
    {
        return a.st+h(a.s)>b.st+h(b.s);
    }
};
priority_queue<dot> q;
signed main(void)
{
    cin>>s;
    q.push({s,0});
    v[s]=1;
    wh(!q.empty())
    {
        dot u=q.top();q.pop();
        if(u.s==t)
        {
            cout<<u.st;
            return 0;
        }
        int z;
        FOR(i,0,8)if(u.s[i]=='0')z=i;
        FOR(i,0,3)
        {
            if(d[i]==1&&z%3==2)continue;
            if(d[i]==-1&&z%3==0)continue;
            int nz=z+d[i];
            if(nz<0||nz>8)continue;
            string ns=u.s;
            swap(ns[z],ns[nz]);
            if(v[ns])continue;
            v[ns]=1;
            q.push({ns,u.st+1});
        }
    }
    cout<<0;
    return false;
}
